if (! function_exists('text_soundex')) {
    function text_soundex($word, $wordlist = null, $max_results = null)
    {
        $word = trim((string)$word);
        if (empty($word)) {
            return json_encode(['error' => 'Word is required', 'soundex' => '']);
        }

        // Canonical PHP soundex is built-in, but let's implement the classic algorithm
        // for educational purposes and to show the mapping
        function classicSoundex($w) {
            $w = mb_strtoupper(trim($w));
            if (empty($w)) return '';
            
            // Keep the first letter
            $first = $w[0];
            $rest = substr($w, 1);
            
            // Soundex mapping
            $map = [
                'B' => '1', 'F' => '1', 'P' => '1', 'V' => '1',
                'C' => '2', 'G' => '2', 'J' => '2', 'K' => '2', 'Q' => '2', 'S' => '2', 'X' => '2', 'Z' => '2',
                'D' => '3', 'T' => '3',
                'L' => '4',
                'M' => '5', 'N' => '5',
                'R' => '6',
            ];
            
            // Vowels and H,W,Y are skipped
            $skip = ['A', 'E', 'I', 'O', 'U', 'Y', 'H', 'W'];
            
            $code = $first;
            $prevDigit = '';
            
            for ($i = 0; $i < strlen($rest) && strlen($code) < 4; $i++) {
                $ch = $rest[$i];
                if (in_array($ch, $skip)) {
                    $prevDigit = '';
                    continue;
                }
                if (isset($map[$ch])) {
                    $digit = $map[$ch];
                    // Skip adjacent same-digit letters (e.g., PF in "Pfister")
                    if ($digit !== $prevDigit) {
                        $code .= $digit;
                        $prevDigit = $digit;
                    }
                }
            }
            
            // Pad or truncate to 4 characters
            $code = str_pad($code, 4, '0');
            $code = substr($code, 0, 4);
            
            return $code;
        }

